const body = $json.body ?? $json;
const normalizeText = (value) => typeof value === 'string' ? value.trim() : '';
const message = normalizeText(body.message);
if (!message) {
  throw new Error('message is required');
}
const sessionId = normalizeText(body.sessionId) || `anon-${Date.now()}`;
const pageUrl = normalizeText(body.pageUrl);
const history = Array.isArray(body.history)
  ? body.history
      .filter((item) => item && typeof item === 'object' && typeof item.content === 'string')
      .slice(-12)
      .map((item) => ({ role: item.role === 'assistant' ? 'assistant' : 'user', content: item.content }))
  : [];
const companyContext = [
  'Empresa: Taktia Automações.',
  'Especialidades: integracao de plataformas, atendimento com IA e automacao de processos.',
  'Cidade: Uberlandia, MG.',
  'Contato: taktia@taktia.com.br e WhatsApp (34) 99859-2724.',
  'Objetivo do chatbot: qualificar leads, responder duvidas comerciais e direcionar para contato humano quando necessario.'
].join(' ');
return [{
  json: {
    sessionId,
    pageUrl,
    chatInput: message,
    history,
    companyContext
  }
}];

const raw = $json.output ?? $json.text ?? $json.message ?? '';
const reply = typeof raw === 'string' ? raw.trim() : JSON.stringify(raw);
return [{
  json: {
    reply,
    source: 'n8n',
    sessionId: $('Prepare Chat Input').first().json.sessionId
  }
}];
